targets.expr:
label_replace(
  max by (image) (
    kube_pod_container_info{
      cluster_name=~"$cluster",
      namespace=~"$ns",
      container=~".*metadata-api.*"
    }
  ),
  "image_tag", "$1", "image", ".*:(.*)"
)

sum by (upstream_host, status_class) (
  label_replace(
    label_replace(
      label_replace(
        rate(forward_call_response_status_count_total{
          cluster_name=~"$cluster", namespace=~"$ns", container="gateway-api-gw"
        }[1m]),
        "status_class", "2xx-3xx", "upstream_status", "[23].."
      ),
      "status_class", "4xx", "upstream_status", "4.."
    ),
    "status_class", "5xx", "upstream_status", "5.."
  )
)

avg_over_time(
  max by (container) (
    container_memory_working_set_bytes{
      cluster_name=~"$cluster", namespace=~"$ns"
    }
  )[$__range:5m]
)

max_over_time(
  max by (container) (
    container_memory_working_set_bytes{
      cluster_name=~"$cluster", namespace=~"$ns"
    }
  )[$__range:5m]
)

100 * max by (container) (
  container_memory_working_set_bytes{
    cluster_name=~"$cluster", namespace=~"$ns"
  }
) / on(container) group_left() max by (container) (
  kube_pod_container_resource_requests{
    cluster_name=~"$cluster", namespace=~"$ns",
    resource="memory", unit="byte"
  }
)

100 * max by (container) (
  container_memory_working_set_bytes{
    cluster_name=~"$cluster", namespace=~"$ns"
  }
) / on(container) group_left() max by (container) (
  kube_pod_container_resource_limits{
    cluster_name=~"$cluster", namespace=~"$ns",
    resource="memory", unit="byte"
  }
)

100 * max by (container) (
  rate(container_cpu_usage_seconds_total{
    cluster_name=~"$cluster",
    namespace=~"${ns}"
  }[$__rate_interval])
)
/ on (container) group_left() max by (container) (
  kube_pod_container_resource_requests{
    cluster_name=~"$cluster",
    namespace=~"${ns}",
    resource="cpu",
    unit="core"
  }
)

sum by (namespace, container) (
  max_over_time(kube_pod_container_status_restarts_total{
    cluster_name=~"$cluster", namespace=~"$ns"
  }[$__range])
)
-
sum by (namespace, container) (
  min_over_time(kube_pod_container_status_restarts_total{
    cluster_name=~"$cluster", namespace=~"$ns"
  }[$__range])
)

sum by (namespace, container) (
  kube_pod_container_status_last_terminated_reason{
    cluster_name=~"$cluster", namespace=~"$ns", reason="OOMKilled"
  }
)

count by (namespace, container) (
  kube_pod_container_status_restarts_total{
    cluster_name=~"$cluster", namespace=~"$ns"
  }
)

max by (namespace, container, pod) (
  kube_pod_container_status_last_terminated_reason{
    cluster_name=~"$cluster", namespace=~"$ns", reason="OOMKilled"
  }
)

max by (namespace, container) (
  kube_pod_start_time{cluster_name=~"$cluster", namespace=~"$ns"} * 1000
  * on(namespace, pod) group_right()
  kube_pod_container_status_last_terminated_reason{
    cluster_name=~"$cluster", namespace=~"$ns", reason="OOMKilled"
  }
)
